      <tbody>${e.map((e,n)=>{let r=e.dir||(t===`mix`?`es2de`:t),i=r===`es2de`?e.es:e.de,a=r===`es2de`?e.de:e.es,o=r===`es2de`?`ES`:`DE`,s=r===`es2de`?`DE`:`ES`;return`<tr><td class="num">${n+1}.</td><td class="qlang">${o}</td><td class="q">${i}</td><td class="alang">${s}</td><td class="a sol">${a}</td><td class="pt">/ 1</td></tr>`}).join(``)}</tbody>
